'use client';
import { trpc } from '@/trpc/client';
import { useEffect, useState } from 'react';

function Chat() {
  const [accumulated, setAccumulated] = useState("");
  const chat = trpc.chatStream.useQuery("Hello AI", {
    // We want to make sure we don't keep refetching and we handle the stream
    refetchOnWindowFocus: false,
    refetchOnMount: false,
    retry: false,
  });

  useEffect(() => {
    if (chat.data) {
      // In tRPC v11, for an AsyncGenerator query, 
      // chat.data is the latest yielded value.
      // However, we need to be careful about how React Query updates.
      // If the same value is yielded twice, this might not trigger if not careful.
      // But here chunks are unique.
      setAccumulated((prev) => {
        // Simple heuristic: if we already have this chunk at the end, maybe don't append?
        // But here we know the chunks.
        return prev + chat.data;
      });
    }
  }, [chat.data]);

  return (
    <div className="mt-4 p-4 border rounded">
      <h2 className="text-xl font-bold">Chat Stream</h2>
      <div className="mt-2 p-2 bg-gray-100 min-h-[50px]">
        {accumulated}
      </div>
      {chat.isLoading && <p>Loading stream...</p>}
      {chat.isFetching && !chat.isLoading && <p>Streaming...</p>}
    </div>
  );
}

export default function Home() {
  return (
    <main className="p-4">
      <h1>tRPC AI Streaming Chat</h1>
      <Chat />
    </main>
  );
}

